import { execution } from '@dynatrace-sdk/automation-utils';
import { entitiesClient } from '@dynatrace-sdk/client-classic-environment-v2';

export default async function ({ executionId }) {
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  try {
    const response = await entitiesClient.listEntities({
      entitySelector: input.entitySelector,
      fields: input.fieldsToReturn ? input.fieldsToReturn.split(',').map(f => f.trim()) : undefined,
      pageSize: parseInt(input.limit)
    });

    // Apply sorting if specified
    let entities = response.entities || [];
    if (input.sorting) {
      const [field, direction] = input.sorting.split('(');
      const dir = direction.replace(')', '');
      entities.sort((a, b) => {
        const aVal = a[field];
        const bVal = b[field];
        if (aVal < bVal) return dir === 'asc' ? -1 : 1;
        if (aVal > bVal) return dir === 'asc' ? 1 : -1;
        return 0;
      });
    }

    console.log(`Found ${entities.length} entities matching selector`);

    return {
      entityCount: entities.length,
      selector: input.entitySelector,
      entities: entities.slice(0, parseInt(input.limit)),
      hasMore: entities.length > parseInt(input.limit)
    };
  } catch (error) {
    console.error('Error querying entities:', error);
    throw new Error(`Failed to query entities: ${error}`);
  }
}
